def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            base_term = (1 / (j**3)) * (ratio ** j)
            modifier = 1 + ((-1)**j) * (0.05 * j)
            score += base_term * modifier
        remaining = capacity - item
        if remaining < 0.03 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.5
        elif remaining < 0.25 * capacity:
            score *= 1.1
        else:
            score *= 0.8
        if int(capacity) % 7 == 0:
            score -= 0.07 * (capacity / 15)
        elif int(capacity) % 4 == 0:
            score -= 0.03 * (capacity / 25)
        else:
            score -= 0.01 * (capacity / 40)
        penalty = 0
        for k in range(1, 6):
            diff = abs(capacity - item * k)
            threshold = 0.015 * capacity
            if diff < threshold:
                penalty += 0.15 * (k**1.5)
            elif diff < 2 * threshold and k % 2 == 0:
                penalty += 0.05 * k
        score += penalty
        if score < 0:
            score = 0
        fluctuation = 0
        for m in range(1, 5):
            fluctuation += np.sin((capacity + item * m) * np.pi / 50) / (m + 1)
        score *= (1 + 0.1 * fluctuation)
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
